27	WeaselSessionId _GenerateNewWeaselSessionId(SessionStatusMap sm, DWORD pid) {
28	  if (sm.empty())
29	    return (WeaselSessionId)(pid + 1);
30	  return (WeaselSessionId)(sm.rbegin()->first + 1);
31	}
