33	int expand_ibus_modifier(int m) {
34	  return (m & 0xff) | ((m & 0xff00) << 16);
35	}
36	
37	RimeWithWeaselHandler::RimeWithWeaselHandler(UI* ui)
38	    : m_ui(ui),
39	      m_active_session(0),
40	      m_disabled(true),
41	      m_current_dark_mode(false),
42	      m_global_ascii_mode(false),
43	      m_show_notifications_time(1200),
44	      _UpdateUICallback(NULL) {
45	  m_ui->InServer() = true;
46	  rime_api = rime_get_api();
47	  assert(rime_api);
48	  m_pid = GetCurrentProcessId();
49	  uint16_t msbit = 0;
50	  for (auto i = 31; i >= 0; i--) {
51	    if (m_pid & (1 << i)) {
52	      msbit = i;
53	      break;
54	    }
55	  }
56	  m_pid = (m_pid << (31 - msbit));
57	  _Setup();
58	}
59	
60	RimeWithWeaselHandler::~RimeWithWeaselHandler() {
61	  m_show_notifications.clear();
62	  m_session_status_map.clear();
