73	void _RefreshTrayIcon(const RimeSessionId session_id,
74	                      const std::function<void()> _UpdateUICallback) {
75	  // Dangerous, don't touch
76	  static char app_name[256] = {0};
77	  auto ret = rime_api->get_property(session_id, "client_app", app_name,
78	                                    sizeof(app_name) - 1);
79	  if (!ret || u8tow(app_name) == std::wstring(L"explorer.exe"))
80	    boost::thread th([=]() {
81	      ::Sleep(100);
82	      if (_UpdateUICallback)
83	        _UpdateUICallback();
84	    });
85	  else if (_UpdateUICallback)
86	    _UpdateUICallback();
87	}
