89	void RimeWithWeaselHandler::_Setup() {
90	  RIME_STRUCT(RimeTraits, weasel_traits);
91	  std::string shared_dir = wtou8(WeaselSharedDataPath().wstring());
92	  std::string user_dir = wtou8(WeaselUserDataPath().wstring());
93	  weasel_traits.shared_data_dir = shared_dir.c_str();
94	  weasel_traits.user_data_dir = user_dir.c_str();
95	  weasel_traits.prebuilt_data_dir = weasel_traits.shared_data_dir;
96	  std::string distribution_name = wtou8(get_weasel_ime_name());
97	  weasel_traits.distribution_name = distribution_name.c_str();
98	  weasel_traits.distribution_code_name = WEASEL_CODE_NAME;
99	  weasel_traits.distribution_version = WEASEL_VERSION;
100	  weasel_traits.app_name = "rime.weasel";
101	  std::string log_dir = WeaselLogPath().u8string();
102	  weasel_traits.log_dir = log_dir.c_str();
103	  rime_api->setup(&weasel_traits);
104	  rime_api->set_notification_handler(&RimeWithWeaselHandler::OnNotify, this);
105	}
106	
107	void RimeWithWeaselHandler::Initialize() {
108	  m_disabled = _IsDeployerRunning();
109	  if (m_disabled) {
110	    return;
111	  }
112	
113	  LOG(INFO) << "Initializing la rime.";
114	  rime_api->initialize(NULL);
115	  if (rime_api->start_maintenance(/*full_check = */ False)) {
116	    m_disabled = true;
117	    rime_api->join_maintenance_thread();
118	  }
119	
120	  RimeConfig config = {NULL};
121	  if (rime_api->config_open("weasel", &config)) {
122	    if (m_ui) {
123	      _UpdateUIStyle(&config, m_ui, true);
124	      _UpdateShowNotifications(&config, true);
125	      m_current_dark_mode = IsUserDarkMode();
126	      if (m_current_dark_mode) {
127	        const int BUF_SIZE = 255;
128	        char buffer[BUF_SIZE + 1] = {0};
129	        if (rime_api->config_get_string(&config, "style/color_scheme_dark",
130	                                        buffer, BUF_SIZE)) {
131	          std::string color_name(buffer);
132	          _UpdateUIStyleColor(&config, m_ui->style(), color_name);
133	        }
134	      }
135	      m_base_style = m_ui->style();
136	    }
137	    Bool global_ascii = false;
138	    if (rime_api->config_get_bool(&config, "global_ascii", &global_ascii))
139	      m_global_ascii_mode = !!global_ascii;
140	    if (!rime_api->config_get_int(&config, "show_notifications_time",
141	                                  &m_show_notifications_time))
142	      m_show_notifications_time = 1200;
143	    _LoadAppOptions(&config, m_app_options);
144	    rime_api->config_close(&config);
145	  }
146	  m_last_schema_id.clear();
147	}
148	
149	void RimeWithWeaselHandler::Finalize() {
150	  m_active_session = 0;
151	  m_disabled = true;
152	  m_session_status_map.clear();
153	  LOG(INFO) << "Finalizing la rime.";
154	  rime_api->finalize();
155	}
156	
157	DWORD RimeWithWeaselHandler::FindSession(WeaselSessionId ipc_id) {
158	  if (m_disabled)
159	    return 0;
160	  Bool found = rime_api->find_session(to_session_id(ipc_id));
161	  DLOG(INFO) << "Find session: session_id = " << to_session_id(ipc_id)
162	             << ", found = " << found;
163	  return found ? (ipc_id) : 0;
164	}
165	
166	DWORD RimeWithWeaselHandler::AddSession(LPWSTR buffer, EatLine eat) {
167	  if (m_disabled) {
168	    DLOG(INFO) << "Trying to resume service.";
169	    EndMaintenance();
170	    if (m_disabled)
171	      return 0;
172	  }
173	  RimeSessionId session_id = (RimeSessionId)rime_api->create_session();
174	  if (m_global_ascii_mode) {
175	    for (const auto& pair : m_session_status_map) {
176	      if (pair.first) {
177	        rime_api->set_option(session_id, "ascii_mode",
178	                             !!pair.second.status.is_ascii_mode);
179	        break;
180	      }
181	    }
182	  }
183	
184	  WeaselSessionId ipc_id =
185	      _GenerateNewWeaselSessionId(m_session_status_map, m_pid);
186	  DLOG(INFO) << "Add session: created session_id = " << session_id
187	             << ", ipc_id = " << ipc_id;
188	  SessionStatus& session_status = new_session_status(ipc_id);
189	  session_status.style = m_base_style;
190	  session_status.session_id = session_id;
191	  _ReadClientInfo(ipc_id, buffer);
192	
193	  RIME_STRUCT(RimeStatus, status);
194	  if (rime_api->get_status(session_id, &status)) {
195	    std::string schema_id = status.schema_id;
196	    m_last_schema_id = schema_id;
197	    _LoadSchemaSpecificSettings(ipc_id, schema_id);
198	    _LoadAppInlinePreeditSet(ipc_id, true);
199	    _UpdateInlinePreeditStatus(ipc_id);
200	    _RefreshTrayIcon(session_id, _UpdateUICallback);
201	    session_status.status = status;
202	    session_status.__synced = false;
203	    rime_api->free_status(&status);
204	  }
205	  m_ui->style() = session_status.style;
206	  // show session's welcome message :-) if any
207	  if (eat) {
208	    _Respond(ipc_id, eat);
209	  }
210	  add_session = true;
211	  _UpdateUI(ipc_id);
212	  add_session = false;
213	  m_active_session = ipc_id;
214	  return ipc_id;
215	}
216	
217	DWORD RimeWithWeaselHandler::RemoveSession(WeaselSessionId ipc_id) {
218	  if (m_ui)
219	    m_ui->Hide();
220	  if (m_disabled)
221	    return 0;
222	  DLOG(INFO) << "Remove session: session_id = " << to_session_id(ipc_id);
223	  // TODO: force committing? otherwise current composition would be lost
224	  rime_api->destroy_session(to_session_id(ipc_id));
225	  m_session_status_map.erase(ipc_id);
226	  m_active_session = 0;
227	  return 0;
228	}
229	
230	void RimeWithWeaselHandler::UpdateColorTheme(BOOL darkMode) {
231	  RimeConfig config = {NULL};
232	  if (rime_api->config_open("weasel", &config)) {
233	    if (m_ui) {
234	      _UpdateUIStyle(&config, m_ui, true);
235	      m_current_dark_mode = darkMode;
236	      if (darkMode) {
237	        const int BUF_SIZE = 255;
238	        char buffer[BUF_SIZE + 1] = {0};
239	        if (rime_api->config_get_string(&config, "style/color_scheme_dark",
240	                                        buffer, BUF_SIZE)) {
241	          std::string color_name(buffer);
242	          _UpdateUIStyleColor(&config, m_ui->style(), color_name);
243	        }
244	      }
245	      m_base_style = m_ui->style();
246	    }
247	    rime_api->config_close(&config);
248	  }
249	
250	  for (auto& pair : m_session_status_map) {
251	    RIME_STRUCT(RimeStatus, status);
252	    if (rime_api->get_status(to_session_id(pair.first), &status)) {
253	      _LoadSchemaSpecificSettings(pair.first, std::string(status.schema_id));
254	      _LoadAppInlinePreeditSet(pair.first, true);
255	      _UpdateInlinePreeditStatus(pair.first);
256	      pair.second.status = status;
257	      pair.second.__synced = false;
258	      rime_api->free_status(&status);
259	    }
260	  }
261	  m_ui->style() = get_session_status(m_active_session).style;
262	}
263	
264	BOOL RimeWithWeaselHandler::ProcessKeyEvent(KeyEvent keyEvent,
265	                                            WeaselSessionId ipc_id,
266	                                            EatLine eat) {
267	  DLOG(INFO) << "Process key event: keycode = " << keyEvent.keycode
268	             << ", mask = " << keyEvent.mask << ", ipc_id = " << ipc_id;
269	  if (m_disabled)
270	    return FALSE;
271	  RimeSessionId session_id = to_session_id(ipc_id);
272	  Bool handled = rime_api->process_key(session_id, keyEvent.keycode,
273	                                       expand_ibus_modifier(keyEvent.mask));
274	  // vim_mode when keydown only
275	  if (!handled && !(keyEvent.mask & ibus::Modifier::RELEASE_MASK)) {
276	    bool isVimBackInCommandMode =
277	        (keyEvent.keycode == ibus::Keycode::Escape) ||
278	        ((keyEvent.mask & (1 << 2)) &&
279	         (keyEvent.keycode == ibus::Keycode::XK_c ||
280	          keyEvent.keycode == ibus::Keycode::XK_C ||
281	          keyEvent.keycode == ibus::Keycode::XK_bracketleft));
282	    if (isVimBackInCommandMode &&
283	        rime_api->get_option(session_id, "vim_mode") &&
284	        !rime_api->get_option(session_id, "ascii_mode")) {
285	      rime_api->set_option(session_id, "ascii_mode", True);
286	    }
287	  }
288	  _Respond(ipc_id, eat);
289	  _UpdateUI(ipc_id);
290	  m_active_session = ipc_id;
291	  return (BOOL)handled;
292	}
