294	void RimeWithWeaselHandler::CommitComposition(WeaselSessionId ipc_id) {
295	  DLOG(INFO) << "Commit composition: ipc_id = " << ipc_id;
296	  if (m_disabled)
297	    return;
298	  rime_api->commit_composition(to_session_id(ipc_id));
299	  _UpdateUI(ipc_id);
300	  m_active_session = ipc_id;
301	}
302	
303	void RimeWithWeaselHandler::ClearComposition(WeaselSessionId ipc_id) {
304	  DLOG(INFO) << "Clear composition: ipc_id = " << ipc_id;
305	  if (m_disabled)
