450	void RimeWithWeaselHandler::_GetCandidateInfo(CandidateInfo& cinfo,
451	                                              RimeContext& ctx) {
452	  cinfo.candies.resize(ctx.menu.num_candidates);
453	  cinfo.comments.resize(ctx.menu.num_candidates);
454	  cinfo.labels.resize(ctx.menu.num_candidates);
455	  for (int i = 0; i < ctx.menu.num_candidates; ++i) {
456	    cinfo.candies[i].str = escape_string(u8tow(ctx.menu.candidates[i].text));
457	    if (ctx.menu.candidates[i].comment) {
458	      cinfo.comments[i].str =
459	          escape_string(u8tow(ctx.menu.candidates[i].comment));
460	    }
461	    if (RIME_STRUCT_HAS_MEMBER(ctx, ctx.select_labels) && ctx.select_labels) {
462	      cinfo.labels[i].str = escape_string(u8tow(ctx.select_labels[i]));
463	    } else if (ctx.menu.select_keys) {
464	      cinfo.labels[i].str =
465	          escape_string(std::wstring(1, ctx.menu.select_keys[i]));
466	    } else {
467	      cinfo.labels[i].str = std::to_wstring((i + 1) % 10);
468	    }
469	  }
470	  cinfo.highlighted = ctx.menu.highlighted_candidate_index;
471	  cinfo.currentPage = ctx.menu.page_no;
472	  cinfo.is_last_page = ctx.menu.is_last_page;
473	}
