620	void RimeWithWeaselHandler::_LoadAppInlinePreeditSet(WeaselSessionId ipc_id,
621	                                                     bool ignore_app_name) {
622	  SessionStatus& session_status = get_session_status(ipc_id);
623	  RimeSessionId session_id = session_status.session_id;
624	  static char _app_name[50];
625	  rime_api->get_property(session_id, "client_app", _app_name,
626	                         sizeof(_app_name) - 1);
627	  std::string app_name(_app_name);
628	  if (!ignore_app_name && m_last_app_name == app_name)
629	    return;
630	  m_last_app_name = app_name;
631	  bool inline_preedit = session_status.style.inline_preedit;
632	  bool found = false;
633	  if (!app_name.empty()) {
634	    auto it = m_app_options.find(app_name);
635	    if (it != m_app_options.end()) {
636	      AppOptions& options(m_app_options[it->first]);
637	      for (const auto& pair : options) {
638	        if (pair.first == "inline_preedit") {
639	          rime_api->set_option(session_id, pair.first.c_str(),
640	                               Bool(pair.second));
641	          session_status.style.inline_preedit = Bool(pair.second);
642	          found = true;
643	          break;
644	        }
645	      }
646	    }
647	  }
648	  if (!found) {
649	    session_status.style.inline_preedit = m_base_style.inline_preedit;
650	    // load from schema.
651	    RIME_STRUCT(RimeStatus, status);
652	    if (rime_api->get_status(session_id, &status)) {
653	      std::string schema_id = status.schema_id;
654	      RimeConfig config;
655	      if (rime_api->schema_open(schema_id.c_str(), &config)) {
656	        Bool value = False;
657	        if (rime_api->config_get_bool(&config, "style/inline_preedit",
658	                                      &value)) {
659	          session_status.style.inline_preedit = value;
660	        }
661	        rime_api->config_close(&config);
662	      }
663	      rime_api->free_status(&status);
664	    }
665	  }
666	  if (session_status.style.inline_preedit != inline_preedit)
667	    _UpdateInlinePreeditStatus(ipc_id);
668	}
