670	bool RimeWithWeaselHandler::_ShowMessage(Context& ctx, Status& status) {
671	  std::lock_guard<std::mutex> lock(m_notifier_mutex);
672	  if (m_message_type.empty() || m_message_value.empty())
673	    return m_ui->IsCountingDown();
674	  // show as auxiliary string
675	  std::wstring& tips(ctx.aux.str);
676	  bool show_icon = false;
677	  if (m_message_type == "deploy") {
678	    if (m_message_value == "start")
679	      if (GetThreadUILanguage() == MAKELANGID(LANG_ENGLISH, SUBLANG_ENGLISH_US))
680	        tips = L"Deploying RIME";
681	      else
682	        tips = L"正在部署 RIME";
683	    else if (m_message_value == "success")
684	      if (GetThreadUILanguage() == MAKELANGID(LANG_ENGLISH, SUBLANG_ENGLISH_US))
685	        tips = L"Deployed";
686	      else
687	        tips = L"部署完成";
688	    else if (m_message_value == "failure") {
689	      if (GetThreadUILanguage() ==
690	          MAKELANGID(LANG_CHINESE, SUBLANG_CHINESE_TRADITIONAL))
691	        tips = L"有錯誤，請查看日誌 %TEMP%\\rime.weasel\\rime.weasel.*.INFO";
692	      else if (GetThreadUILanguage() ==
693	               MAKELANGID(LANG_CHINESE, SUBLANG_CHINESE_SIMPLIFIED))
694	        tips = L"有错误，请查看日志 %TEMP%\\rime.weasel\\rime.weasel.*.INFO";
695	      else
696	        tips =
697	            L"There is an error, please check the logs "
698	            L"%TEMP%\\rime.weasel\\rime.weasel.*.INFO";
699	    }
700	  } else if (m_message_type == "schema") {
701	    tips = /*L"【" + */ status.schema_name /* + L"】"*/;
702	  } else if (m_message_type == "option") {
703	    status.type = SCHEMA;
704	    if (m_message_value == "!ascii_mode") {
705	      show_icon = true;
706	    } else if (m_message_value == "ascii_mode") {
707	      show_icon = true;
708	    } else
709	      tips = u8tow(m_message_label);
710	
711	    if (m_message_value == "full_shape" || m_message_value == "!full_shape")
712	      status.type = FULL_SHAPE;
713	  }
714	  auto counter = m_ui->IsCountingDown();
715	  if (!show_icon && counter)
716	    return counter;
717	  auto foption = m_show_notifications.find(m_option_name);
718	  auto falways = m_show_notifications.find("always");
719	  if ((!add_session && (foption != m_show_notifications.end() ||
720	                        falways != m_show_notifications.end())) ||
721	      m_message_type == "deploy") {
722	    m_ui->Update(ctx, status);
723	    if (m_show_notifications_time)
724	      m_ui->ShowWithTimeout(m_show_notifications_time);
725	    return true;
726	  } else {
727	    return m_ui->IsCountingDown();
728	  }
729	}
