737	
738	bool RimeWithWeaselHandler::_Respond(WeaselSessionId ipc_id, EatLine eat) {
739	  std::wstring body;
740	  body.reserve(4096);
741	  std::vector<const char*> actions;
742	  actions.reserve(8);
743	
744	  SessionStatus& session_status = get_session_status(ipc_id);
745	  RimeSessionId session_id = session_status.session_id;
746	  RIME_STRUCT(RimeCommit, commit);
747	  if (rime_api->get_commit(session_id, &commit)) {
748	    actions.push_back("commit");
749	    std::wstring commit_text_w = escape_string(u8tow(commit.text));
750	    body.append(L"commit=").append(commit_text_w).append(L"\n");
751	    rime_api->free_commit(&commit);
752	  }
753	
754	  bool is_composing = false;
755	  RIME_STRUCT(RimeStatus, status);
756	  static const std::wstring Bool_wstring[] = {L"0", L"1"};
757	  if (rime_api->get_status(session_id, &status)) {
758	    is_composing = !!status.is_composing;
759	    actions.push_back("status");
760	    body.append(L"status.ascii_mode=")
761	        .append(Bool_wstring[!!status.is_ascii_mode])
762	        .append(L"\n")
763	        .append(L"status.composing=")
764	        .append(Bool_wstring[!!status.is_composing])
765	        .append(L"\n")
766	        .append(L"status.disabled=")
767	        .append(Bool_wstring[!!status.is_disabled])
768	        .append(L"\n")
769	        .append(L"status.full_shape=")
770	        .append(Bool_wstring[!!status.is_full_shape])
771	        .append(L"\n")
772	        .append(L"status.schema_id=")
773	        .append(status.schema_id ? u8tow(status.schema_id) : std::wstring())
774	        .append(L"\n");
775	    if (m_global_ascii_mode &&
776	        (session_status.status.is_ascii_mode != status.is_ascii_mode)) {
777	      for (auto& pair : m_session_status_map) {
778	        if (pair.first != ipc_id)
779	          rime_api->set_option(to_session_id(pair.first), "ascii_mode",
780	                               !!status.is_ascii_mode);
781	      }
782	    }
783	    session_status.status = status;
784	    rime_api->free_status(&status);
785	  }
786	
787	  RIME_STRUCT(RimeContext, ctx);
788	  if (rime_api->get_context(session_id, &ctx)) {
789	    bool has_candidates = ctx.menu.num_candidates > 0;
790	    CandidateInfo cinfo;
791	    if (has_candidates) {
792	      _GetCandidateInfo(cinfo, ctx);
793	    }
794	    if (is_composing) {
795	      const auto& preedit = ctx.composition.preedit;
796	      const auto& start = ctx.composition.sel_start;
797	      const auto& end = ctx.composition.sel_end;
798	      const auto& cursor = ctx.composition.cursor_pos;
799	      static const auto u8towstring = [](const char* u8str, int len = 0) {
800	        return std::to_wstring(utf8towcslen(u8str, len));
801	      };
802	      actions.push_back("ctx");
803	      switch (session_status.style.preedit_type) {
804	        case UIStyle::PREVIEW: {
805	          if (ctx.commit_text_preview) {
806	            const char* first_utf8 = ctx.commit_text_preview;
807	            const size_t first_len = std::strlen(first_utf8);
808	            const std::wstring first_w = escape_string(u8tow(first_utf8));
809	            const std::wstring tmp = u8towstring(first_utf8, (int)first_len);
810	            body.append(L"ctx.preedit=")
811	                .append(first_w)
812	                .append(L"\n")
813	                .append(L"ctx.preedit.cursor=")
814	                .append(u8towstring(first_utf8, 0))
815	                .append(L",")
816	                .append(tmp)
817	                .append(L",")
818	                .append(tmp)
819	                .append(L"\n");
820	            break;
821	          }
822	          // no preview, fall back to composition
823	        }
824	        case UIStyle::COMPOSITION: {
825	          body.append(L"ctx.preedit=")
826	              .append(escape_string(u8tow(preedit)))
827	              .append(L"\n");
828	          if (start <= end) {
829	            body.append(L"ctx.preedit.cursor=")
830	                .append(u8towstring(preedit, start))
831	                .append(L",")
832	                .append(u8towstring(preedit, end))
833	                .append(L",")
834	                .append(u8towstring(preedit, cursor))
835	                .append(L"\n");
836	          }
837	          break;
838	        }
839	        case UIStyle::PREVIEW_ALL: {
840	          body.append(L"ctx.preedit=")
841	              .append(escape_string(u8tow(preedit)))
842	              .append(L"  [");
843	          auto label_valid = session_status.style.label_font_point > 0;
844	          auto comment_valid = session_status.style.comment_font_point > 0;
845	          const std::wstring mark_text_w =
846	              session_status.style.mark_text.empty()
847	                  ? std::wstring(L"*")
848	                  : session_status.style.mark_text;
849	          for (auto i = 0; i < ctx.menu.num_candidates; i++) {
850	            std::wstring label_w;
851	            if (label_valid) {
852	              wchar_t buf_lbl[128];
853	              swprintf_s<128>(buf_lbl,
854	                              session_status.style.label_text_format.c_str(),
855	                              cinfo.labels.at(i).str.c_str());
856	              label_w = std::wstring(buf_lbl);
857	            }
858	            std::wstring comment_w =
859	                comment_valid ? cinfo.comments.at(i).str : std::wstring();
860	            std::wstring prefix_w = (i != ctx.menu.highlighted_candidate_index)
861	                                        ? std::wstring()
862	                                        : mark_text_w;
863	            body.append(L" ")
864	                .append(prefix_w)
865	                .append(escape_string(label_w))
866	                .append(escape_string(u8tow(ctx.menu.candidates[i].text)))
867	                .append(L" ")
868	                .append(escape_string(comment_w));
869	          }
870	          body.append(L" ]\n");
871	          if (start <= end) {
872	            body.append(L"ctx.preedit.cursor=")
873	                .append(u8towstring(preedit, start))
874	                .append(L",")
875	                .append(u8towstring(preedit, end))
876	                .append(L",")
877	                .append(u8towstring(preedit, cursor))
878	                .append(L"\n");
879	          }
880	          break;
881	        }
882	      }
883	    }
884	    if (has_candidates) {
885	      std::wstringstream ss;
886	      boost::archive::text_woarchive oa(ss);
887	
888	      oa << cinfo;
889	
890	      auto s = ss.str();
891	      body.append(L"ctx.cand=").append(std::move(s)).append(L"\n");
892	    }
893	    rime_api->free_context(&ctx);
894	  }
895	
896	  // configuration information
897	  actions.push_back("config");
898	  body.append(L"config.inline_preedit=")
899	      .append(std::to_wstring((int)session_status.style.inline_preedit))
900	      .append(L"\n");
901	
902	  // style
903	  if (!session_status.__synced) {
904	    std::wstringstream ss;
905	    boost::archive::text_woarchive oa(ss);
906	    oa << session_status.style;
907	
908	    actions.push_back("style");
909	    body.append(L"style=").append(ss.str()).append(L"\n");
910	    session_status.__synced = true;
911	  }
912	
913	  // summarize: send header first to avoid vector head-insert cost
914	  std::wstring header;
915	  if (actions.empty()) {
916	    header = L"action=noop\n";
917	  } else {
918	    std::string actionList;
919	    actionList.reserve(64);
920	    for (size_t i = 0; i < actions.size(); ++i) {
921	      if (i > 0)
922	        actionList += ',';
923	      actionList += actions[i];
924	    }
925	    header = std::wstring(L"action=") + u8tow(actionList) + L"\n";
926	  }
927	  if (!eat(header))
928	    return false;
929	
930	  body.append(L".\n");
931	  if (!eat(body))
932	    return false;
933	
934	  return true;
935	}
