1057	// parse string option to T type value, with fallback
1058	template <typename T, size_t N>
1059	void _RimeParseStringOptWithFallback(RimeConfig* config,
1060	                                     const char* key,
1061	                                     T& value,
1062	                                     const Array<T, N>& arr,
1063	                                     const T& fallback) {
1064	  char str_buff[256] = {0};
1065	  if (rime_api->config_get_string(config, key, str_buff, 255)) {
1066	    for (size_t i = 0; i < N; ++i) {
1067	      if (strcmp(arr[i].first, str_buff) == 0) {
1068	        value = arr[i].second;
1069	        return;
1070	      }
1071	    }
1072	  }
1073	  value = fallback;
