1076	template <typename T>
1077	void _RimeGetIntStr(RimeConfig* config,
1078	                    const char* key,
1079	                    T& value,
1080	                    const char* fb_key = nullptr,
1081	                    const void* fb_value = nullptr,
1082	                    const std::function<void(T&)>& func = nullptr) {
1083	  if constexpr (std::is_same<T, int>::value) {
1084	    if (!rime_api->config_get_int(config, key, &value) && fb_key != 0)
1085	      rime_api->config_get_int(config, fb_key, &value);
1086	  } else if constexpr (std::is_same<T, std::wstring>::value) {
1087	    const int BUF_SIZE = 2047;
1088	    char buffer[BUF_SIZE + 1] = {0};
1089	    if (rime_api->config_get_string(config, key, buffer, BUF_SIZE) ||
1090	        rime_api->config_get_string(config, fb_key, buffer, BUF_SIZE)) {
1091	      value = u8tow(buffer);
1092	    } else if (fb_value) {
1093	      value = *(T*)fb_value;
1094	    }
1095	  }
1096	  if (func)
1097	    func(value);
1098	}
