1100	// Helper to iterate a Rime map and invoke callback with key/path
1101	static void ForEachRimeMap(
1102	    RimeConfig* config,
1103	    const std::string& path,
1104	    const std::function<void(const char* key, const char* child_path)>& cb) {
1105	  RimeConfigIterator iter;
1106	  if (!rime_api->config_begin_map(&iter, config, path.c_str()))
1107	    return;
1108	  while (rime_api->config_next(&iter)) {
1109	    cb(iter.key, iter.path);
1110	  }
1111	  rime_api->config_end(&iter);
1112	}
