1303	                 style.round_corner, "style/layout/round_corner", 0, _abs);
1304	  // corner_radius not set, fallback to round_corner
1305	  _RimeGetIntStr(config, "style/layout/corner_radius", style.round_corner_ex,
1306	                 "style/layout/round_corner", 0, _abs);
1307	  // fix padding and spacing settings
1308	  if (style.layout_type != UIStyle::LAYOUT_VERTICAL_TEXT) {
1309	    // hilite_padding vs spacing
1310	    // if hilite_padding over spacing, increase spacing
1311	    style.spacing = max(style.spacing, style.hilite_padding_y * 2);
1312	    // hilite_padding vs candidate_spacing
1313	    if (style.layout_type == UIStyle::LAYOUT_VERTICAL_FULLSCREEN ||
1314	        style.layout_type == UIStyle::LAYOUT_VERTICAL) {
1315	      // vertical, if hilite_padding_y over candidate spacing,
1316	      // increase candidate spacing
1317	      style.candidate_spacing =
1318	          max(style.candidate_spacing, style.hilite_padding_y * 2);
1319	    } else {
1320	      // horizontal, if hilite_padding_x over candidate
1321	      // spacing, increase candidate spacing
1322	      style.candidate_spacing =
1323	          max(style.candidate_spacing, style.hilite_padding_x * 2);
1324	    }
1325	    // hilite_padding_x vs hilite_spacing
1326	    if (!style.inline_preedit)
1327	      style.hilite_spacing = max(style.hilite_spacing, style.hilite_padding_x);
1328	  } else  // LAYOUT_VERTICAL_TEXT
1329	  {
1330	    // hilite_padding_x vs spacing
1331	    // if hilite_padding over spacing, increase spacing
1332	    style.spacing = max(style.spacing, style.hilite_padding_x * 2);
1333	    // hilite_padding vs candidate_spacing
1334	    // if hilite_padding_x over candidate
1335	    // spacing, increase candidate spacing
1336	    style.candidate_spacing =
1337	        max(style.candidate_spacing, style.hilite_padding_x * 2);
1338	    // vertical_text_with_wrap and hilite_padding_y over candidate_spacing
1339	    if (style.vertical_text_with_wrap)
1340	      style.candidate_spacing =
1341	          max(style.candidate_spacing, style.hilite_padding_y * 2);
1342	    // hilite_padding_y vs hilite_spacing
1343	    if (!style.inline_preedit)
1344	      style.hilite_spacing = max(style.hilite_spacing, style.hilite_padding_y);
1345	  }
1346	  // fix padding and margin settings
1347	  int scale = style.margin_x < 0 ? -1 : 1;
1348	  style.margin_x = scale * max(style.hilite_padding_x, abs(style.margin_x));
1349	  scale = style.margin_y < 0 ? -1 : 1;
1350	  style.margin_y = scale * max(style.hilite_padding_y, abs(style.margin_y));
1351	  // get enhanced_position
1352	  _RimeGetBool(config, "style/enhanced_position", initialize,
1353	               style.enhanced_position, true, false);
1354	  // get color scheme
1355	  const int BUF_SIZE = 255;
1356	  char buffer[BUF_SIZE + 1] = {0};
1357	  if (initialize && rime_api->config_get_string(config, "style/color_scheme",
1358	                                                buffer, BUF_SIZE))
1359	    _UpdateUIStyleColor(config, style);
1360	}
