1388	    COLOR("candidate_text_color", style.candidate_text_color, style.text_color);
1389	    COLOR("candidate_back_color", style.candidate_back_color, 0);
1390	    COLOR("border_color", style.border_color, style.text_color);
1391	    COLOR("hilited_text_color", style.hilited_text_color, style.text_color);
1392	    COLOR("hilited_back_color", style.hilited_back_color, style.back_color);
1393	    COLOR("hilited_candidate_text_color", style.hilited_candidate_text_color,
1394	          style.hilited_text_color);
1395	    COLOR("hilited_candidate_back_color", style.hilited_candidate_back_color,
1396	          style.hilited_back_color);
1397	    COLOR("hilited_candidate_shadow_color",
1398	          style.hilited_candidate_shadow_color, 0);
1399	    COLOR("hilited_shadow_color", style.hilited_shadow_color, 0);
1400	    COLOR("candidate_shadow_color", style.candidate_shadow_color, 0);
1401	    COLOR("candidate_border_color", style.candidate_border_color, 0);
1402	    COLOR("hilited_candidate_border_color",
1403	          style.hilited_candidate_border_color, 0);
1404	    COLOR("label_color", style.label_text_color,
1405	          blend_colors(style.candidate_text_color, style.candidate_back_color));
1406	    COLOR("hilited_label_color", style.hilited_label_text_color,
1407	          blend_colors(style.hilited_candidate_text_color,
1408	                       style.hilited_candidate_back_color));
1409	    COLOR("comment_text_color", style.comment_text_color,
1410	          style.label_text_color);
1411	    COLOR("hilited_comment_text_color", style.hilited_comment_text_color,
1412	          style.hilited_label_text_color);
1413	    COLOR("hilited_mark_color", style.hilited_mark_color, 0);
1414	#undef COLOR
1415	    return true;
1416	  }
1417	  return false;
