14	inline std::wstring getUsername() {
15	  DWORD len = 0;
16	  GetUserName(NULL, &len);
17	
18	  if (len <= 0) {
19	    return L"";
20	  }
21	
22	  wchar_t* username = new wchar_t[len + 1];
23	
24	  GetUserName(username, &len);
25	  if (len <= 0) {
26	    delete[] username;
27	    return L"";
28	  }
29	  auto res = std::wstring(username);
30	  delete[] username;
31	  return res;
32	}
33	
34	// data directories
35	std::filesystem::path WeaselSharedDataPath();
36	std::filesystem::path WeaselUserDataPath();
37	inline fs::path WeaselLogPath() {
38	  WCHAR _path[MAX_PATH] = {0};
39	  // default location
40	  ExpandEnvironmentStringsW(L"%TEMP%\\rime.weasel", _path, _countof(_path));
41	  fs::path path = fs::path(_path);
42	  if (!fs::exists(path)) {
43	    fs::create_directories(path);
44	  }
45	  return path;
46	}
47	
48	inline BOOL IsUserDarkMode() {
49	  constexpr const LPCWSTR key =
50	      L"Software\\Microsoft\\Windows\\CurrentVersion\\Themes\\Personalize";
51	  constexpr const LPCWSTR value = L"AppsUseLightTheme";
52	
53	  DWORD type;
54	  DWORD data;
55	  DWORD size = sizeof(DWORD);
56	  LSTATUS st = RegGetValue(HKEY_CURRENT_USER, key, value, RRF_RT_REG_DWORD,
57	                           &type, &data, &size);
58	
59	  if (st == ERROR_SUCCESS && type == REG_DWORD)
60	    return data == 0;
61	  return false;
62	}
63	
64	inline std::wstring string_to_wstring(const std::string& str,
65	                                      int code_page = CP_ACP) {
66	  // support CP_ACP and CP_UTF8 only
67	  if (code_page != 0 && code_page != CP_UTF8)
68	    return L"";
69	  // calc len
70	  int len =
71	      MultiByteToWideChar(code_page, 0, str.c_str(), (int)str.size(), NULL, 0);
