};

#define HR(result) HR_Impl(result, __FILE__, __LINE__)

inline void HR_Impl(HRESULT const result, const char* file, int line) {
  if (S_OK != result) {
    DebugStream() << "[" << current_time() << " " << file << ":" << line << "] "
                  << HRESULTToString(result);
    throw ComException(result);
  }
}
